const fs = require("hexo-fs");
const path = require("path");

const statusMap = {
  wantWatch: "想看",
  watching: "在看",
  watched: "看过",
};

const splitTags = (value) =>
  String(value)
    .split(/[,，/]/)
    .map((tag) => tag.trim())
    .filter(Boolean);

const normalizeTags = (item) => {
  const tags = [];
  [item.type, item.area, item.tags].flat().filter(Boolean).forEach((tag) => {
    tags.push(...splitTags(tag));
  });
  return [...new Set(tags)];
};

const normalizeCover = (cover) => {
  if (!cover || !/^https?:\/\//i.test(cover)) return cover;
  try {
    const url = new URL(cover);
    const source = `${url.host}${url.pathname}`;
    return `https://images.weserv.nl/?url=${encodeURIComponent(source)}`;
  } catch (error) {
    return cover;
  }
};

const normalizeItem = (item = {}, status) => {
  const id = item.id || item.media_id;
  const cover = item.cover || item.image;
  return {
    ...item,
    title: item.title || item.name,
    origin_title: item.origin_title || item.originTitle || item.original_title,
    cover: normalizeCover(cover),
    url: item.url || item.link || (id ? `https://www.bilibili.com/bangumi/media/md${id}/` : item.source_url),
    status: item.status || status,
    rating: item.rating || item.score,
    episodes: item.episodes || item.totalCount,
    year: item.year,
    tags: normalizeTags(item),
    summary: item.summary || item.des || item.description,
    source_url: item.source_url,
  };
};

const readPluginItems = () => {
  const file = path.join(hexo.source_dir, "_data", "bangumis.json");
  if (!fs.existsSync(file)) return [];

  try {
    const data = JSON.parse(fs.readFileSync(file));
    return Object.keys(statusMap).flatMap((key) => {
      const list = Array.isArray(data[key]) ? data[key] : [];
      return list.map((item) => normalizeItem(item, statusMap[key]));
    });
  } catch (error) {
    hexo.log.warn(`Failed to read bangumis.json: ${error.message}`);
    return [];
  }
};

const getBangumiPage = (locals) => {
  const pages = locals.pages || [];
  return pages.findOne
    ? pages.findOne({ layout: "bangumi" }) || pages.findOne({ path: "bangumi/index.html" })
    : null;
};

hexo.extend.generator.register("bangumi", function (locals) {
  const bangumiPage = getBangumiPage(locals);
  const manualItems = Array.isArray(bangumiPage?.bangumi)
    ? bangumiPage.bangumi.map((item) => normalizeItem(item, item.status))
    : [];
  const pluginItems = readPluginItems();
  const result = pluginItems.length ? pluginItems : manualItems;

  if (bangumiPage) bangumiPage.bangumi_items = result;
  hexo.locals.set("bangumi_items", () => result);
});
